resources.preRequestScript:
const runId = Date.now().toString();
const start = new Date(Date.now() + 5 * 60 * 1000);
const end = new Date(start.getTime() + 60 * 60 * 1000);
insomnia.baseEnvironment.set('run_id', runId);
insomnia.baseEnvironment.set('start_at', start.toISOString());
insomnia.baseEnvironment.set('end_at', end.toISOString());

resources.afterResponseScript:
const body = insomnia.response.json();
insomnia.baseEnvironment.set('admin_token', body.access_token);
insomnia.test('administrator login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('facility_id', body.id);
insomnia.test('facility creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
const connectorId = body.connectors[0].id;
insomnia.baseEnvironment.set('station_id', body.id);
insomnia.baseEnvironment.set('connector_id', connectorId);
insomnia.test('station creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('station response contains a Connector ID', () => insomnia.expect(connectorId).to.be.a('string'));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('driver_id', body.id);
insomnia.test('driver creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('driver_token', body.access_token);
insomnia.test('driver login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('vehicle_id', body.id);
insomnia.test('vehicle creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('reservation_id', body.reservation.id);
insomnia.test('reservation creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('reservation starts CONFIRMED', () => insomnia.expect(body.reservation.status).to.eql('CONFIRMED'));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('session_id', body.id);
insomnia.test('activation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('session is ACTIVE', () => insomnia.expect(body.status).to.eql('ACTIVE'));

const body = insomnia.response.json();
const connector = body.connectors.find(item => item.id === insomnia.baseEnvironment.get('connector_id'));
insomnia.test('station detail returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('station contains the Connector', () => insomnia.expect(connector).to.be.an('object'));
insomnia.test('connector is Charging', () => insomnia.expect(connector.status).to.eql('Charging'));

const body = insomnia.response.json();
insomnia.test('session list returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('created session is listed', () => insomnia.expect(body.some(item => item.id === insomnia.baseEnvironment.get('session_id'))).to.eql(true));

const body = insomnia.response.json();
insomnia.test('completion returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('session is COMPLETED', () => insomnia.expect(body.status).to.eql('COMPLETED'));
insomnia.test('ended_at is populated', () => insomnia.expect(body.ended_at).to.not.eql(null));

const body = insomnia.response.json();
const connector = body.connectors.find(item => item.id === insomnia.baseEnvironment.get('connector_id'));
insomnia.test('station detail returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('station contains the Connector', () => insomnia.expect(connector).to.be.an('object'));
insomnia.test('connector is Available', () => insomnia.expect(connector.status).to.eql('Available'));

const body = insomnia.response.text();
insomnia.test('metrics returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('activation counter is exposed', () => insomnia.expect(body).to.include('scep_charging_sessions_activated_total'));
insomnia.test('completion counter is exposed', () => insomnia.expect(body).to.include('scep_charging_sessions_completed_total'));
